<?php
namespace Tests\Feature\Hr;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Analytics\Actions\BuildHrAnalyticsSnapshotAction;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Personnel\Models\HrEmployee;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class AnalyticsWorkflowTest extends TestCase{use RefreshHrDatabase;public function test_snapshot_is_tenant_scoped_and_source_traced():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$user=User::factory()->create(['role_id'=>$role]);$this->actingAs($user);$tenant=LegalEntity::create(['user_id'=>$user->id,'name'=>'Analitik','tax_number'=>'9393939393','is_active'=>true]);app(TenantContext::class)->set($tenant);HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$tenant->id,'employee_number'=>'AN1','national_id_encrypted'=>'enc','national_id_hash'=>'analytics-one','national_id_last_four'=>'0001','first_name'=>'Aktif','last_name'=>'Çalışan','status'=>'active']);$snapshot=app(BuildHrAnalyticsSnapshotAction::class)->execute(today()->startOfYear()->toDateString(),today()->toDateString());$this->assertSame(1,$snapshot->metrics['headcount']);$this->assertSame('hr_employees.status',$snapshot->sources['headcount']);$this->assertSame(64,strlen($snapshot->source_hash));$this->assertDatabaseHas('activity_logs',['action'=>'hr_analytics_snapshot_generated']);}}
